import { gameStore } from './game';

function createReadonlyStore(selector) {
	return {
		subscribe(run) {
			return gameStore.subscribe(($gameStore) => run(selector($gameStore)));
		},
	};
}

export const grid = {
	...createReadonlyStore(($gameStore) => $gameStore.puzzleGrid),

	getSencode() {
		return gameStore.getSencode();
	},
};

export const userGrid = createReadonlyStore(($gameStore) => $gameStore.grid);
export const invalidCells = createReadonlyStore(($gameStore) => $gameStore.invalidCells);
